# scripts/adr_review_checker.py
# Run daily (e.g. via CI/CD cron job) to notify when ADR reviews are due.

import json, pathlib, datetime, smtplib
from email.mime.text import MIMEText

ADR_DIR = pathlib.Path("docs/adr")
REVIEW_LEAD_DAYS = 14   # notify 14 days before the review date

def parse_review_date(adr_path: pathlib.Path) -> datetime.date | None:
    text = adr_path.read_text()
    for line in text.splitlines():
        if line.startswith("Next scheduled review:"):
            date_str = line.split(":", 1)[1].strip()
            try:
                return datetime.date.fromisoformat(date_str)
            except ValueError:
                return None
    return None

def parse_status(adr_path: pathlib.Path) -> str:
    text = adr_path.read_text()
    for line in text.splitlines():
        if line.startswith("Status:"):
            return line.split(":", 1)[1].strip()
    return "Unknown"

def check_reviews():
    today = datetime.date.today()
    due_soon = []
    overdue = []

    for adr_path in sorted(ADR_DIR.glob("ADR-*.md")):
        status = parse_status(adr_path)
        if status not in ("Accepted",):
            continue
        review_date = parse_review_date(adr_path)
        if review_date is None:
            overdue.append((adr_path.name, "No review date set"))
            continue
        days_until = (review_date - today).days
        if days_until < 0:
            overdue.append((adr_path.name, f"Overdue by {-days_until} days ({review_date})"))
        elif days_until <= REVIEW_LEAD_DAYS:
            due_soon.append((adr_path.name, f"Due in {days_until} days ({review_date})"))

    return due_soon, overdue

if __name__ == "__main__":
    due_soon, overdue = check_reviews()
    if due_soon or overdue:
        lines = ["ADR REVIEW REMINDER", "===================", ""]
        if overdue:
            lines.append("OVERDUE:")
            for name, msg in overdue:
                lines.append(f"  {name}: {msg}")
            lines.append("")
        if due_soon:
            lines.append("DUE WITHIN 14 DAYS:")
            for name, msg in due_soon:
                lines.append(f"  {name}: {msg}")
        print("\n".join(lines))
